{
  "schema_version": 1,
  "request_id": "rf-suggest-edit-efficiency-range-ordering-001",
  "project": "radishflow",
  "task": "suggest_flowsheet_edits",
  "status": "success",
  "requires_confirmation": true,
  "answers": [
    {
      "summary": "当前围绕已选中的泵单元 pump-3 的效率参数越界警告生成一个最小候选修正提案。",
      "issues": [
        {
          "title": "泵效率参数超出推荐范围",
          "description": "Range Review Pump 的 efficiency_percent 当前为 109，诊断指出该值超出推荐运行范围，并且最新快照显示求解状态为 invalid_parameters。",
          "severity": "warning",
          "target": {
            "type": "unit",
            "id": "pump-3"
          },
          "citations": [
            "diag-1",
            "flowdoc-unit-1",
            "snapshot-1"
          ]
        }
      ],
      "proposed_actions": [
        {
          "action": "candidate_edit",
          "title": "为 pump-3 的效率参数提供回到有效区间的候选占位修正",
          "target": {
            "type": "unit",
            "id": "pump-3"
          },
          "rationale": "诊断直接指出 pump-3 的 efficiency_percent=109 超出推荐运行范围；为避免直接替用户决定最终设计值，建议仅在该单元上提供一个局部参数候选更新，占位为需确认的有效效率百分比。",
          "patch": {
            "parameter_updates": {
              "config.efficiency_percent": {
                "from": 109,
                "to_placeholder": "确认后的有效效率百分比，建议设置为不超过 100 且符合该泵设计/运行假设的值"
              }
            }
          },
          "risk_level": "medium",
          "requires_confirmation": true,
          "citations": [
            "diag-1",
            "flowdoc-unit-1",
            "snapshot-1"
          ],
          "confidence": 0.86
        }
      ]
    }
  ]
}
